import sailpoint.tools.JsonHelper;
import sailpoint.tools.Util;

if (Util.isNotNullOrEmpty(groupPrimaryEmail)) {

  String[] strArray = groupPrimaryEmail.split("@");

   if (strArray.length == 2) {

      intendedGroupName = strArray[0];

      if (Util.isNotNullOrEmpty(intendedGroupName)) {

         workflow.put("groupName", intendedGroupName);

      }

   }

  result = createCloudGroup(intendedGroupName, groupPrimaryEmail, "C04h4ias1", groupDescription);

  logger.info("createCloudGroup Method Result: " + result);
  
  jsonMap = JsonHelper.mapFromJson(String.class, String.class, JsonHelper.makePretty(result)).get("response");
  
  rawName = jsonMap.get("name");
  
  return rawName.replace("groups/",""); //objectId of the created GWS group

}

import sailpoint.tools.Util;

if (Util.isNotNullOrEmpty(groupPrimaryEmail)) {

  result = makeCloudGroupRestricted(groupPrimaryEmail);

  logger.info("makeCloudGroupRestrictedMethod Result: " + result);

}

import sailpoint.object.Identity;

Identity workgroup = createWorkgroupForCollibra(groupName);

if (workgroup != null) {

   populateCollibraWorkgroup(groupOwner, workgroup, groupName);

}
